sys_script_include.script:
var HistoryList = Class.create();
HistoryList.prototype = Object.extendsObject(BaseTableProvider, {
    initialize: function (options) {
        options = options || {};

        BaseTableProvider.prototype.initialize.call(this, options);

        this.limit =
            parseInt(
                (this.providerParams && this.providerParams.limit) ||
                    options.limit ||
                    this.configObject.limit ||
                    10,
                10
            ) || 10;

        this.navigatorHistory = new NavigatorHistory({
            transactionId: this.transactionId,
            limit: this.getTableLimit()
        });
    },

    getRowClickAction: function () {
        return {
            target: "row",
            action: {
                type: "link",
                urlField: "url"
            }
        };
    },

    getCellContent: function (field, record) {
        if (field.name === "title") {
            return {
                layout: "stack",
                blocks: [
                    { value: record.title || "" },
                    {
                        value: record.subtitle || "",
                        className: "scm-table-cell-muted"
                    }
                ]
            };
        }

        if (field.name === "lastAccessed") {
            return {
                layout: "stack",
                blocks: [{ value: record.lastAccessedLabel || "" }]
            };
        }

        return {
            layout: "stack",
            blocks: [{ value: record[field.name] || "" }]
        };
    },

    getHistoryEntries: function () {
        try {
            return this.navigatorHistory.getHistoryEntries().map(
                function (entry) {
                    return {
                        url: entry.url,
                        title: entry.title || entry.url,
                        subtitle: entry.subtitle || "",
                        lastAccessed: entry.lastAccessed || "",
                        lastAccessedLabel: this._formatTimeAgo(entry.lastAccessed)
                    };
                },
                this
            );
        } catch (error) {
            this.logger.error({
                method: "getHistoryEntries",
                message: "Error getting history entries",
                error: error.message
            });
            return [];
        }
    },

    getTableData: function () {
        return this.getHistoryEntries();
    },

    getTableLimit: function () {
        return this.limit;
    },

    getTotalRecords: function () {
        return this.getHistoryEntries().length;
    },

    _initializeConfigObject: function () {
        return {
            table: Constants.NAVIGATION_HISTORY_TABLE,
            static_query: "",
            show_new_record_button: "false",
            can_filter: "false",
            can_save_preferences: "false",
            can_configure_columns: "false",
            show_applied_filters: "false",
            show_table_metadata: "false",
            page_title: "",
            detail_view_page: "",
            id_field: "url",
            order_by: "lastAccessed",
            order_direction: "DESC",
            limit: "10",
            columns: [
                {
                    name: "title",
                    label: "",
                    default: true,
                    width: "68%",
                    minWidth: "0"
                },
                {
                    name: "lastAccessed",
                    label: "",
                    default: true,
                    width: "32%",
                    minWidth: "0"
                }
            ],
            filter_fields: [],
            breadcrumbs: []
        };
    },

    _formatTimeAgo: function (dateTimeValue) {
        if (!dateTimeValue) {
            return "";
        }

        try {
            var now = new GlideDateTime();
            var past = new GlideDateTime(dateTimeValue);
            var diffMillis = now.getNumericValue() - past.getNumericValue();

            if (isNaN(diffMillis) || diffMillis <= 0) {
                return "just now";
            }

            var seconds = Math.floor(diffMillis / 1000);

            if (seconds < 60) {
                return "just now";
            }

            var minutes = Math.floor(seconds / 60);
            if (minutes < 60) {
                return minutes + (minutes === 1 ? " minute ago" : " minutes ago");
            }

            var hours = Math.floor(minutes / 60);
            if (hours < 24) {
                return hours + (hours === 1 ? " hour ago" : " hours ago");
            }

            var days = Math.floor(hours / 24);
            if (days < 7) {
                return days + (days === 1 ? " day ago" : " days ago");
            }

            var weeks = Math.floor(days / 7);
            if (weeks < 4) {
                return weeks + (weeks === 1 ? " week ago" : " weeks ago");
            }

            var months = Math.floor(days / 30);
            if (months < 12) {
                return months + (months === 1 ? " month ago" : " months ago");
            }

            var years = Math.floor(days / 365);
            return years + (years === 1 ? " year ago" : " years ago");
        } catch (error) {
            this.logger.error({
                method: "_formatTimeAgo",
                message: "Error formatting relative time",
                error: error.message,
                dateTimeValue: dateTimeValue
            });
            return dateTimeValue;
        }
    },

    type: "HistoryList"
});
